  AND v.date_achat IS NULL;

-- Vérification : voir les camions en inventaire avec leur âge
SELECT
  stock_numero,
  marque,
  modele,
  annee,
  date_achat,
  (CURRENT_DATE - date_achat::date) AS age_jours
FROM prod_ventes
WHERE statut = 'inventaire'
  AND date_achat IS NOT NULL
ORDER BY age_jours DESC
LIMIT 30;
